    def get_provisioning_uri(self, account_name, issuer_name="MFA_System"):
        """
        Generates a provisioning URI (otpauth://) for QR code generation.
        https://github.com/google/google-authenticator/wiki/Key-Uri-Format

        :param account_name: The user's account name (e.g., email address).
        :param issuer_name: The name of the issuing organization.
        :return: A string representing the provisioning URI.
        """
        secret_b32 = base64.b32encode(self.secret).decode().rstrip('=')
        # Encode components for URL safety
        account_name_encoded = quote(account_name)
        issuer_name_encoded = quote(issuer_name)

        params = {
            'secret': secret_b32,
            'issuer': issuer_name,
            'algorithm': self.algorithm.upper(),
            'digits': self.digits,
            'period': self.interval
        }
        query_string = urlencode(params)
        uri = f"otpauth://totp/{issuer_name_encoded}:{account_name_encoded}?{query_string}"
        return uri

    def generate_qr_code(self, account_name, issuer_name="MFA_System", filename="totp_qr.png"):
        """
        Generates and saves a QR code image for provisioning.

        :param account_name: The user's account name.
        :param issuer_name: The name of the issuing organization.
        :param filename: The name of the file to save the QR code image.
        :return: The filename of the saved QR code.
        """
        uri = self.get_provisioning_uri(account_name, issuer_name)
        img = qrcode.make(uri)
        img.save(filename)
        return filename

